## 4.4 PM Scheduler (Tactical)

### 4.4.1 Purpose

Schedule preventive maintenance for the 12-week tactical horizon, respecting track availability, labor capacity, and material constraints.

### 4.4.2 Implementation

```typescript
interface TacticalSchedulerConfig {
  horizonWeeks: number;           // 12
  materialCheckDaysHard: number;  // 14 (hard constraint)
  materialCheckDaysSoft: number;  // 90 (soft constraint)
  trackUtilizationTarget: number; // 0.85
}

class TacticalPMScheduler {
  async schedule(depotId: string): Promise<SchedulingResult> {
    const config = this.config;
    const horizonEnd = addWeeks(new Date(), config.horizonWeeks);

    // 1. Get pending PMs that need scheduling
    const pendingPMs = await this.getPendingPMs(depotId, horizonEnd);

    // 2. Get resource availability
    const trackAvailability = await this.getTrackAvailability(depotId, horizonEnd);
    const laborCapacity = await this.getLaborCapacity(depotId, horizonEnd);
    const materialPositions = await this.getMaterialPositions(depotId);

    // 3. Sort PMs by priority (urgency, criticality)
    const sortedPMs = this.prioritizePMs(pendingPMs);

    // 4. Schedule each PM
    const scheduled: ScheduledPM[] = [];
    const deferred: DeferredPM[] = [];
    const materialWarnings: MaterialWarning[] = [];

    for (const pm of sortedPMs) {
      const result = await this.scheduleSinglePM(
        pm,
        trackAvailability,
        laborCapacity,
        materialPositions,
        scheduled
      );

      if (result.scheduled) {
        scheduled.push(result.scheduled);

        // Reserve materials
        await this.reserveMaterials(result.scheduled, materialPositions);

        // Update availability
        this.updateAvailability(
          result.scheduled,
          trackAvailability,
          laborCapacity
        );
      } else {
        deferred.push({
          pm,
          reason: result.reason,
          suggestedDate: result.suggestedDate
        });
      }

      if (result.materialWarning) {
        materialWarnings.push(result.materialWarning);
      }
    }

    // 5. Persist schedule
    await this.persistSchedule(scheduled, deferred);

    // 6. Notify if material blocks exist
    if (materialWarnings.length > 0) {
      await this.notifyMaterialBlocks(materialWarnings);
    }

    return {
      scheduled,
      deferred,
      materialWarnings,
      summary: {
        totalPMs: sortedPMs.length,
        scheduledCount: scheduled.length,
        deferredCount: deferred.length,
        trackUtilization: this.calculateTrackUtilization(trackAvailability),
        laborUtilization: this.calculateLaborUtilization(laborCapacity)
      }
    };
  }

  private async scheduleSinglePM(
    pm: PendingPM,
    trackAvailability: TrackAvailability[],
    laborCapacity: LaborCapacity[],
    materialPositions: MaterialPosition[],
    alreadyScheduled: ScheduledPM[]
  ): Promise<ScheduleAttemptResult> {
    const pmType = pm.pmType;

    // Find valid dates within compliance window
    const validDates = this.getValidDates(
      pm.constraintStart,
      pm.constraintEnd,
      pmType.minTrackDays
    );

    for (const targetDate of validDates) {
      // Check track availability
      const track = this.findAvailableTrack(
        targetDate,
        pmType.trackType,
        pmType.minTrackDays,
        trackAvailability
      );

      if (!track) continue;

      // Check labor capacity
      const laborOk = this.checkLaborCapacity(
        targetDate,
        pmType.estimatedHours,
        laborCapacity
      );

      if (!laborOk) continue;

      // Check material availability
      const materialCheck = await this.checkMaterialAvailability(
        pm,
        targetDate,
        materialPositions
      );

      if (materialCheck.blocked) {
        // Within hard constraint window - cannot schedule
        if (this.isWithinHardWindow(targetDate)) {
          return {
            scheduled: null,
            reason: `Material unavailable: ${materialCheck.missingParts.join(', ')}`,
            suggestedDate: materialCheck.suggestedDate,
            materialWarning: {
              pmId: pm.id,
              trainId: pm.trainId,
              missingParts: materialCheck.missingParts,
              expectedAvailability: materialCheck.expectedDelivery
            }
          };
        }
        // Soft constraint window - add warning but continue
        continue;
      }

      // Schedule found!
      return {
        scheduled: {
          pmId: pm.id,
          trainId: pm.trainId,
          pmTypeId: pmType.id,
          targetDate,
          trackId: track.id,
          assignedHours: pmType.estimatedHours,
          constraintStart: pm.constraintStart,
          constraintEnd: pm.constraintEnd
        },
        reason: null,
        materialWarning: materialCheck.warning
      };
    }

    // No valid slot found
    return {
      scheduled: null,
      reason: 'No available slot within compliance window',
      suggestedDate: addDays(pm.constraintEnd, 7)
    };
  }

  private async checkMaterialAvailability(
    pm: PendingPM,
    targetDate: Date,
    materialPositions: MaterialPosition[]
  ): Promise<MaterialCheckResult> {
    const requirements = await this.getPMRequirements(pm.pmType.id);
    const missingParts: string[] = [];
    let earliestDelivery: Date | null = null;

    for (const req of requirements) {
      if (req.criticality === 'CONSUMABLE') continue;

      const position = materialPositions.find(
        p => p.partNumber === req.partNumber && p.depotId === pm.depotId
      );

      const available = position?.quantityAvailable || 0;

      if (available < req.quantityPerPM) {
        if (req.criticality === 'BLOCKING') {
          missingParts.push(req.partNumber);

          if (position?.nextDeliveryDate) {
            const delivery = new Date(position.nextDeliveryDate);
            if (!earliestDelivery || delivery < earliestDelivery) {
              earliestDelivery = delivery;
            }
          }
        }
      }
    }

    return {
      blocked: missingParts.length > 0 && 
               this.isWithinHardWindow(targetDate),
      missingParts,
      expectedDelivery: earliestDelivery,
      suggestedDate: earliestDelivery 
        ? addDays(earliestDelivery, 1)
        : null,
      warning: missingParts.length > 0 ? {
        type: 'LOW_STOCK',
        parts: missingParts,
        message: `Parts may be unavailable: ${missingParts.join(', ')}`
      } : null
    };
  }
}
```

### 4.4.3 PM Schedule Management Service

Handles manual PM modifications (drag-and-drop, manual reschedules) with full validation including Maximo status locks.

```typescript
/**
 * Service for manual PM schedule modifications.
 * 
 * CRITICAL: All modifications MUST validate against Maximo status to prevent
 * race conditions with in-progress work orders. The PMEditValidator from the
 * Integration layer (Part 7) provides this validation.
 * 
 * Operational reality (Maximo) MUST override planning data (MMS).
 */
class PMScheduleManagementService {
  private pmEditValidator: PMEditValidator;  // From Part 7
  private auditLogger: AuditLogger;

  /**
   * Move a PM to a new date (e.g., from canvas drag-and-drop).
   * 
   * @throws MaximoLockError if PM is in-progress in Maximo
   * @throws ComplianceWindowError if new date is outside allowed window
   * @throws TrackConflictError if track is occupied on new date
   */
  async movePM(
    pmId: string,
    newTargetDate: Date,
    newTrackId: string | null,
    userId: string
  ): Promise<PMScheduleRecord> {

    // 1. CRITICAL: Validate Maximo status lock
    const editValidation = await this.pmEditValidator.validateEdit(pmId);

    if (!editValidation.valid) {
      throw new PMEditBlockedError(
        editValidation.reason,
        editValidation.message,
        {
          maximoStatus: editValidation.maximoStatus,
          maximoWonum: editValidation.maximoWonum,
          suggestion: editValidation.suggestion
        }
      );
    }

    // 2. Load PM with all relationships
    const pm = await this.db.query.pmSchedule.findFirst({
      where: eq(pmSchedule.id, pmId),
      with: {
        pmType: true,
        train: true,
        assignedTrack: true
      }
    });

    if (!pm) {
      throw new NotFoundError('PM not found');
    }

    // 3. Validate compliance window
    if (newTargetDate < pm.constraintStart || newTargetDate > pm.constraintEnd) {
      throw new ComplianceWindowError(
        `Target date ${newTargetDate.toISOString().split('T')[0]} is outside compliance window`,
        {
          constraintStart: pm.constraintStart,
          constraintEnd: pm.constraintEnd,
          requestedDate: newTargetDate
        }

