  2526→    } else {
  2527→      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
  2528→    }
  2529→  }
  2530→  
  2531→  /**
  2532→   * Find all PM codes that satisfy a target PM code.
  2533→   * Returns the target itself plus any higher-level PMs that include it in satisfiesCodes.
  2534→   * 
  2535→   * Example: For C2, returns ['C2', 'C3', 'C4', 'OH'] because C3/C4/OH all satisfy C2.
  2536→   */
  2537→  private getSatisfyingCodes(targetCode: string, allRules: PMType[]): string[] {
  2538→    const result = [targetCode];
  2539→    
  2540→    for (const rule of allRules) {
  2541→      if (rule.satisfiesCodes?.includes(targetCode)) {
  2542→        result.push(rule.pmCode);
  2543→      }
  2544→    }
  2545→    
  2546→    return result;
  2547→  }
