  async generatePlan(
    fromBaseline: string | null
  ): Promise<StrategicPlanResult> {
    // 1. Load current fleet state
    const fleetState = await this.getFleetState();

    // 2. Project PM requirements for each train
    const pmRequirements = await this.projectPMRequirements(
      fleetState,
      this.config.horizonYears
    );

    // 3. Generate constraint envelopes for each quarter
    const envelopes = await this.generateEnvelopes();

    // 4. Run genetic algorithm
    const bestPlan = await this.runGeneticAlgorithm(
      pmRequirements,
      envelopes
    );

    // 5. Validate against constraint envelopes
    const validation = await this.validatePlan(bestPlan, envelopes);

    if (!validation.valid) {
      // Attempt repair
      const repairedPlan = await this.repairPlan(bestPlan, validation);
      return {
        plan: repairedPlan,
        validation: await this.validatePlan(repairedPlan, envelopes),
        metrics: this.calculateMetrics(repairedPlan)
      };
    }

    return {
      plan: bestPlan,
      validation,
      metrics: this.calculateMetrics(bestPlan)
    };
  }

  /**
   * Project PM requirements for all trains over the planning horizon.
   * 
   * CRITICAL: This implementation correctly handles:
   * 1. PM hierarchy (C4 satisfies C1/C2/C3 - resets their counters)
   * 2. Dual triggers (mileage OR time, whichever comes first)
   * 3. Recent velocity calculation for accurate projections
   * 4. Cascading projections (each PM feeds into next cycle)
   */
  private async projectPMRequirements(
    fleetState: FleetState,
    horizonYears: number
  ): Promise<PMRequirement[]> {
    const requirements: PMRequirement[] = [];
    const horizonEnd = addYears(new Date(), horizonYears);

    for (const train of fleetState.trains) {
      const trainRules = await this.getPMRulesForFleet(train.fleetId);
      const trainHistory = await this.getPMHistoryForTrain(train.id);

      // Calculate daily utilization for this train
      const dailyKm = this.calculateDailyUtilization(train, trainHistory);

      // Project all PM types for this train
      const trainProjections = await this.projectTrainPMs(
        train,
        trainRules,
        trainHistory,
        horizonEnd,
        dailyKm
      );

      requirements.push(...trainProjections);
    }

    return requirements;
  }

  /**
   * Project all PM events for a single train over the horizon.
   */
  private async projectTrainPMs(
    train: Train,
    pmRules: PMType[],
    pmHistory: PMHistory[],
    horizonEnd: Date,
    dailyKm: number
  ): Promise<PMRequirement[]> {
    const projections: PMRequirement[] = [];

    // Create working state (mutable copy of history + projections)
    let workingHistory = [...pmHistory];
    let currentMileage = train.currentMileageKm;
    let currentDate = new Date();

    // Project until we exceed horizon
    while (currentDate < horizonEnd) {
      // Find next PM due across all PM types
      let nextPM: { 
        rule: PMType; 
        date: Date; 
        mileage: number; 
        trigger: 'MILEAGE' | 'TIME' 
      } | null = null;

      for (const rule of pmRules) {
        const projection = this.calculateNextPMDue(
          train,
          rule,
          pmRules,
          workingHistory,
          currentMileage,
          currentDate,
          dailyKm
        );

        if (!nextPM || projection.date < nextPM.date) {
          nextPM = {
            rule,
            date: projection.date,
            mileage: projection.mileage,
            trigger: projection.trigger
          };
        }
      }

      if (!nextPM || nextPM.date > horizonEnd) break;

      // Create requirement
      const requirement: PMRequirement = {
        id: generateUUID(),
        trainId: train.id,
        trainNumber: train.trainNumber,
        pmTypeId: nextPM.rule.id,
        pmCode: nextPM.rule.pmCode,
        projectedDate: nextPM.date,
        projectedMileageKm: nextPM.mileage,
        triggerType: nextPM.trigger,
        confidence: workingHistory.length > 0 ? 'HISTORICAL' : 'ESTIMATED',
        estimatedHours: nextPM.rule.estimatedHours,
        trackType: nextPM.rule.trackType,
        durationDays: nextPM.rule.minTrackDays,
        // Compliance window (Ã‚Â±10% of interval by default)
        constraintStart: addDays(nextPM.date, -Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm)),
        constraintEnd: addDays(nextPM.date, Math.round(nextPM.rule.intervalKm * 0.1 / dailyKm))
      };

      projections.push(requirement);

      // Add to working history for cascading projection
      workingHistory.push({
        id: requirement.id,
        trainId: train.id,
        pmTypeId: nextPM.rule.id,
        pmCode: nextPM.rule.pmCode,
        completionDate: nextPM.date,
        mileageAtCompletion: nextPM.mileage
      });

      // Advance state past this PM
      currentDate = addDays(nextPM.date, nextPM.rule.minTrackDays);
      currentMileage = nextPM.mileage + (nextPM.rule.minTrackDays * dailyKm * 0.1);
    }

    return projections;
  }

  /**
   * Calculate when the next instance of a specific PM type is due.
   * 
   * CRITICAL: Accounts for PM hierarchy - a C4 satisfies C1/C2/C3 requirements,
   * so the mileage counter resets from the C4 completion point.
   * 
   * CRITICAL: Handles "Cold Start" case where train has no PM history.
   * Without this fix, trains with high mileage and no history would show
   * ALL PMs as overdue immediately.
   */
  private calculateNextPMDue(
    train: Train,
    targetRule: PMType,
    allRules: PMType[],
    history: PMHistory[],
    currentMileage: number,
    currentDate: Date,
    dailyKm: number
  ): { date: Date; mileage: number; trigger: 'MILEAGE' | 'TIME' } {

    // 1. Find all PM types that SATISFY the target PM
    // (the target itself + any higher-level PM that includes target in satisfiesCodes)
    const satisfyingCodes = this.getSatisfyingCodes(targetRule.pmCode, allRules);

    // 2. Find the most recent PM that satisfies this requirement
    const lastSatisfying = history
      .filter(h => satisfyingCodes.includes(h.pmCode))
      .sort((a, b) => b.mileageAtCompletion - a.mileageAtCompletion)[0];

    // 3. Handle "Cold Start" - no PM history exists
    //    Assume train has been maintained on schedule since commissioning.
    //    Calculate which cycle we're currently in and when it started.
    let lastMileage: number;
    let lastDate: Date;

    if (lastSatisfying) {
      // Normal case: use actual history
      lastMileage = lastSatisfying.mileageAtCompletion;
      lastDate = new Date(lastSatisfying.completionDate);
    } else {
      // COLD START FIX: Create "virtual" last PM
      // Calculate how many complete cycles since commissioning
      const cyclesCompleted = Math.floor(currentMileage / targetRule.intervalKm);

      if (cyclesCompleted > 0) {
        // Assume last PM occurred at start of current cycle
        lastMileage = cyclesCompleted * targetRule.intervalKm;
        // Estimate when that mileage was reached
        const daysAgo = (currentMileage - lastMileage) / dailyKm;
        lastDate = addDays(currentDate, -daysAgo);
      } else {
        // Train hasn't completed first cycle yet - use commissioning as baseline
        lastMileage = 0;
        lastDate = train.commissioningDate;
      }
    }

    // 4. Calculate mileage-based due date
    const kmSinceLast = currentMileage - lastMileage;
    const kmRemaining = Math.max(0, targetRule.intervalKm - kmSinceLast);
    const daysUntilMileageDue = kmRemaining / dailyKm;
    const dateByMileage = addDays(currentDate, daysUntilMileageDue);
    const mileageAtDue = currentMileage + kmRemaining;

    // 5. Calculate time-based due date (if interval defined)
    let dateByTime: Date | null = null;
    if (targetRule.intervalMonths) {
      dateByTime = addMonths(lastDate, targetRule.intervalMonths);
    }

    // 6. Return whichever comes first (dual trigger)
    if (dateByTime && dateByTime < dateByMileage) {
      const daysUntilTime = differenceInDays(dateByTime, currentDate);
      const mileageAtTime = currentMileage + (Math.max(0, daysUntilTime) * dailyKm);
      return { date: dateByTime, mileage: mileageAtTime, trigger: 'TIME' };
    } else {
      return { date: dateByMileage, mileage: mileageAtDue, trigger: 'MILEAGE' };
    }
  }

  /**
   * Find all PM codes that satisfy a target PM code.
   * Returns the target itself plus any higher-level PMs that include it in satisfiesCodes.
   * 
   * Example: For C2, returns ['C2', 'C3', 'C4', 'OH'] because C3/C4/OH all satisfy C2.
   */
  private getSatisfyingCodes(targetCode: string, allRules: PMType[]): string[] {
    const result = [targetCode];

    for (const rule of allRules) {
      if (rule.satisfiesCodes?.includes(targetCode)) {
        result.push(rule.pmCode);
      }
    }

    return result;
  }

  /**
   * Calculate daily mileage rate for a train.
   * Uses recent velocity (between last 2 PMs) if available for accuracy,
   * falls back to lifetime average from commissioning date.
   */

