## 4.7 Baseline Service

### 4.7.1 Purpose

Manage published plan baselines for drift analysis and scenario comparison.

### 4.7.2 Implementation

```typescript
class BaselineService {
  async publishBaseline(
    name: string,
    description: string,
    userId: string
  ): Promise<PlanBaseline> {
    // 1. Validate current plan has no critical conflicts
    const validation = await this.validatePlanForPublishing();
    if (!validation.valid) {
      throw new ValidationError(
        'Cannot publish baseline with critical conflicts',
        validation.conflicts
      );
    }

    // 2. Generate version number
    const latestBaseline = await this.getLatestBaseline();
    const version = this.incrementVersion(latestBaseline?.version || 'v0.0');

    // 3. Create baseline record
    const baseline = await this.db.transaction(async (tx) => {
      // Create baseline
      const [baselineRecord] = await tx.insert(planBaselines)
        .values({
          name,
          description,
          version,
          baselineDate: new Date(),
          horizonEnd: addYears(new Date(), 10),
          status: 'PUBLISHED',
          createdBy: userId,
          publishedBy: userId,
          publishedAt: new Date(),
          fleetCount: await this.getActiveTrainCount(),
          totalPmScheduled: await this.getScheduledPMCount(),
          totalManhoursProjected: await this.getTotalProjectedHours()
        })
        .returning();

      // Snapshot PM schedule
      await tx.execute(sql`
        INSERT INTO baseline_pm_schedule 
          (baseline_id, train_id, pm_type_id, projected_date, projected_mileage_km, assigned_depot_id, assigned_hours)
        SELECT 
          ${baselineRecord.id},
          train_id,
          pm_type_id,
          target_date,
          target_mileage_km,
          assigned_depot_id,
          assigned_hours
        FROM pm_schedule
        WHERE scenario_id IS NULL
          AND status IN ('SCHEDULED', 'IN_PROGRESS')
          AND target_date >= CURRENT_DATE
      `);

      // Snapshot mileage projections
      const projections = await this.generateMileageProjections(
        baselineRecord.horizonEnd
      );

      for (const proj of projections) {
        await tx.insert(baselineMileageProjection)
          .values({
            baselineId: baselineRecord.id,
            trainId: proj.trainId,
            projectionDate: proj.date,
            projectedCumulativeKm: proj.projectedKm,
            dailyRateKm: proj.dailyRate
          });
      }

      // Supersede previous baseline
      if (latestBaseline) {
        await tx.update(planBaselines)
          .set({
            status: 'SUPERSEDED',
            supersededBy: baselineRecord.id,
            supersededAt: new Date()
          })
          .where(eq(planBaselines.id, latestBaseline.id));
      }

      return baselineRecord;
    });

    // 4. Audit log
    await this.auditLog.record({
      entityType: 'plan_baseline',
      entityId: baseline.id,
      action: 'PUBLISH',
      userId,
      newValues: { name, version, description }
    });

    // 5. Notify
    await this.notificationService.notify({
      type: 'BASELINE_PUBLISHED',
      title: `New baseline published: ${version}`,
      body: description,
      recipients: await this.getPlannerUserIds()
    });

    return baseline;
  }

  private async generateMileageProjections(
    horizonEnd: Date
  ): Promise<MileageProjection[]> {
    const trains = await this.db.query.trains.findMany({
      where: eq(trains.active, true)
    });

    const projections: MileageProjection[] = [];

    for (const train of trains) {
      // Calculate average daily mileage from last 30 days
      const recentMileage = await this.db.query.mileageReadings.findMany({
        where: and(
          eq(mileageReadings.trainId, train.id),
          gte(mileageReadings.readingDate, subDays(new Date(), 30)),
          eq(mileageReadings.validationStatus, 'VALID')
        )
      });

      const avgDailyKm = recentMileage.length > 0
        ? recentMileage.reduce((sum, r) => sum + (r.dailyKm || 0), 0) / recentMileage.length
        : 150;  // Default if no history

      // Project forward at monthly intervals
      let currentKm = train.currentMileageKm;
      let currentDate = new Date();

      while (currentDate < horizonEnd) {
        currentDate = addMonths(currentDate, 1);
        currentKm += avgDailyKm * 30;

        projections.push({
          trainId: train.id,
          date: currentDate,
          projectedKm: Math.round(currentKm),
          dailyRate: Math.round(avgDailyKm)
        });
      }
    }

    return projections;
  }
}
