    93→  isOverdue: boolean;
    94→  lastPmDate: string | null;
    95→  lastPmMileageKm: number | null;
    96→}
    97→
    98→/** Compliance window for scheduling */
    99→export interface ComplianceWindow {
   100→  startDate: string;
   101→  endDate: string;
   102→  startMileageKm: number | null;
   103→  endMileageKm: number | null;
   104→  idealDate: string;
   105→  idealMileageKm: number | null;
   106→}
   107→
   108→/** Material availability check result */
   109→export interface MaterialAvailability {
   110→  partNumber: string;
   111→  partDescription: string | null;
   112→  criticality: MaterialCriticality;
   113→  requiredQuantity: number;
   114→  availableQuantity: number;
   115→  depotId: string;
