/**
 * MMS Costing Service
 *
 * Calculates TCO (Total Cost of Ownership) projections, tracks variance against budget,
 * and provides cost impact analysis for schedule adjustments.
 *
 * Key responsibilities:
 * - Calculate individual PM costs (labor + materials + overhead)
 * - Project 12-year TCO with inflation and NPV calculations
 * - Track budget vs. actual cost variance
 * - Support depot-level and global cost analysis
 *
 * Cost calculation components:
 * - Labor: Hours × shop rate with shift multipliers
 * - Materials: Part costs from PM material requirements
 * - Overhead: 18% of direct costs (industry standard)
 *
 * Financial parameters (12-year contract):
 * - Inflation: 3% annually
 * - Discount rate: 5% for NPV calculations
 * - Variance tolerance: 10% before flagging as over-budget
 *
 * @see specs/004-domain-services.md Section 4.10
 */

import { eq, and, gte, lte, isNull, sql, desc } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  pmSchedule,
  pmTypes,
  pmMaterialRequirements,
  laborRates,
  materialCosts,
  costBaselines,
  manhourAdjustments,
} from '../lib/db/schema';
import { NotFoundError } from '../lib/errors';
import { costingMetrics } from '../lib/metrics';

/** PM schedule record type (inferred from schema) */
type PmScheduleRecord = typeof pmSchedule.$inferSelect;

/** PM type record (inferred from schema) */
type PmTypeRecord = typeof pmTypes.$inferSelect;

// =============================================================================
// Constants
// =============================================================================

/** Overhead rate applied to direct costs (labor + materials) */
export const OVERHEAD_RATE = 0.18;

/** Annual inflation rate for TCO projections */
export const INFLATION_RATE = 0.03;

/** Discount rate for NPV calculations */
export const DISCOUNT_RATE = 0.05;

/** Default TCO projection horizon in years (contract period) */
export const DEFAULT_HORIZON_YEARS = 12;

/** Budget variance tolerance before flagging as over-budget */
export const VARIANCE_TOLERANCE = 0.10;

/** Overtime multiplier for night shift (default if not in labor rates) */
export const DEFAULT_OVERTIME_MULTIPLIER = 1.35;

/** Weekend multiplier (default if not in labor rates) */
export const DEFAULT_WEEKEND_MULTIPLIER = 1.5;

/** Default shop rate if not configured (SGD/hour) */
export const DEFAULT_SHOP_RATE = 85.0;

/** Contractor cost multiplier (contractors cost 2x regular labor) */
export const CONTRACTOR_COST_MULTIPLIER = 2.0;

// =============================================================================
// Types
// =============================================================================

/** Detailed cost breakdown for a PM */
export interface CostBreakdown {
  laborCost: number;
  overtimeCost: number;
  materialCost: number;
  contractorCost: number;
  overheadCost: number;
  totalCost: number;
}

/** Yearly cost projection for TCO */
export interface YearlyCost {
  fiscalYear: number;
  laborCost: number;
  materialCost: number;
  totalCost: number;
  pmCount: number;
  inflationFactor: number;
}

/**
 * MMS Man-hour Leveling Service
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods. Prevents overload/underutilization
 * of depot maintenance resources over the tactical planning horizon.
 *
 * Key responsibilities:
 * - Calculate raw man-hour projections from PM schedule
 * - Identify overloaded and underutilized weeks
 * - Apply leveling strategies in priority order
 * - Persist projections and adjustments
 * - Support approval workflow for adjustments
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
 * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
 * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Utilization Targets:
 * - Target: 85%
 * - Minimum: 70% (underutilized below this)
 * - Maximum: 100% (overloaded above this)
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import {
  eq,
  and,
  gte,
  lte,
  desc,
  asc,
  sql,
  inArray,
  isNull,
  or,
  count,
  type SQL,
} from 'drizzle-orm';
import {
  addDays,
  addWeeks,
  startOfWeek,
  endOfWeek,
  format,
  differenceInWeeks,
  parseISO,
  isBefore,
  isAfter,
} from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  manhourCapacity,
  manhourProjections,
  manhourAdjustments,
  pmSchedule,
  pmTypes,
  depots,
  trains,
  laborRates,
  type ManhourCapacity,
  type ManhourProjection,
  type ManhourAdjustment,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';

// =============================================================================
// Constants
// =============================================================================

/** Minimum utilization percentage (underutilized below this) */
const MIN_UTILIZATION = 0.7;

/** Maximum utilization percentage (overloaded above this) */
const MAX_UTILIZATION = 1.0;

/** Default base labor rate per hour (SGD) */
const DEFAULT_BASE_RATE = 85;

/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
const MIN_SHIFT_HOURS = 8;

/** Minimum overtime hours to add */
const MIN_OVERTIME_HOURS = 4;

// =============================================================================
// Types
// =============================================================================

/** Leveling strategy types */
export type AdjustmentType =
  | 'ADVANCE_PM'
  | 'DEFER_PM'
  | 'ADD_OVERTIME'
  | 'CROSS_DEPOT'

