    12→ * - Explanation traces for every assignment decision
    13→ *
    14→ * @see specs/002-architecture.md Section 2.4
    15→ * @see specs/004-domain-services.md Section 4.3
    16→ */
    17→
    18→import { spawn, type Subprocess } from 'bun';
    19→import { logger } from '../lib/logging/logger';
    20→import { withSpan, recordSpanError } from '../lib/tracing';
    21→import { OptimizerError } from '../lib/errors';
    22→import { optimizerMetrics } from '../lib/metrics';
    23→import { FallbackOptimizer, fallbackOptimizer } from './fallback';
